 {"id":"frankenredis-wlbm","title":"Skip maxmemory eviction loop for read commands","description":"Maxmemory enforcement currently runs eviction loop for all commands, including reads. This can evict keys on GET and overwrites last eviction info. Redis enforces maxmemory only on write-ish commands. Fix by skipping eviction loop when command does not advance replication offset; add regression test.","status":"closed","priority":2,"issue_type":"bug","created_at":"2026-04-11T13:33:15.320732752Z","created_by":"ubuntu","updated_at":"2026-04-11T13:34:10.016405378Z","closed_at":"2026-04-11T13:34:10.016149878Z","close_reason":"Skip maxmemory eviction loop for read commands; add regression test","source_repo":".","compaction_level":0,"original_size":0}
